import React, { useState } from 'react';
import { Form } from "./ui/form";
import { Input } from "./ui/input";
import { Textarea } from "./ui/textarea";
import { Label } from "./ui/label";
import { Button } from "./ui/button";
import { Popover, PopoverTrigger, PopoverContent } from "./ui/popover";
import { Calendar } from "./ui/calendar";

function PostTask({ currentUser }) {
  const [form, setForm] = useState({ title: '', description: '', tags: '', budget: '', deadline: '' });
  const [success, setSuccess] = useState(false);
  const [datePickerOpen, setDatePickerOpen] = useState(false);

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setSuccess(false);
    await fetch('http://localhost:8080/api/tasks', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...form, poster: { id: currentUser.id } })
    });
    setSuccess(true);
    setForm({ title: '', description: '', tags: '', budget: '', deadline: '' });
  };

  return (
    <div className="flex justify-center items-center min-h-[70vh] bg-gray-50">
      <Form onSubmit={handleSubmit}>
        <h2 className="text-2xl font-bold mb-6 text-center">Post a Task</h2>
        {success && <div className="text-green-600 text-center mb-2">Task posted!</div>}

        <div>
          <Label htmlFor="title">Title</Label>
          <Input name="title" id="title" placeholder="Title" value={form.title} onChange={handleChange} required />
        </div>
        <div>
          <Label htmlFor="description">Description</Label>
          <Textarea name="description" id="description" placeholder="Describe your task" value={form.description} onChange={handleChange} required />
        </div>
        <div>
          <Label htmlFor="tags">Tags</Label>
          <Input name="tags" id="tags" placeholder="Tags (comma separated)" value={form.tags} onChange={handleChange} />
        </div>
        <div>
          <Label htmlFor="budget">Budget (₹)</Label>
          <Input name="budget" id="budget" placeholder="Budget (₹)" type="number" value={form.budget} onChange={handleChange} required />
        </div>
        <div>
          <Label htmlFor="deadline">Deadline</Label>
          <div className="relative flex gap-2">
            <Input
              id="deadline"
              name="deadline"
              value={form.deadline}
              placeholder="Select a date"
              className="bg-background pr-10"
              onChange={e => setForm({ ...form, deadline: e.target.value })}
              onKeyDown={e => {
                if (e.key === "ArrowDown") {
                  e.preventDefault();
                  setDatePickerOpen(true);
                }
              }}
              autoComplete="off"
            />
            <Popover open={datePickerOpen} onOpenChange={setDatePickerOpen}>
              <PopoverTrigger asChild>
                <Button type="button" variant="ghost" className="absolute top-1/2 right-2 size-6 -translate-y-1/2">
                  <span role="img" aria-label="calendar">📅</span>
                  <span className="sr-only">Select date</span>
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto overflow-hidden p-0" align="end" alignOffset={-8} sideOffset={10}>
                <Calendar
                  mode="single"
                  selected={form.deadline ? new Date(form.deadline) : undefined}
                  month={form.deadline ? new Date(form.deadline) : undefined}
                  onMonthChange={date => {}}
                  onSelect={date => {
                    if (date) {
                      setForm({ ...form, deadline: date.toISOString().slice(0, 10) });
                      setDatePickerOpen(false);
                    }
                  }}
                />
              </PopoverContent>
            </Popover>
          </div>
        </div>
        <Button type="submit">Post Task</Button>
      </Form>
    </div>
  );
}

export default PostTask;
